import std::cmp::min;
import std::vec::Vec;

fn solve(landStartTime: Array<Int64>, landDuration: Array<Int64>, waterStartTime: Array<Int64>, waterDuration: Array<Int64>) -> Int64 {
    let n_land = landStartTime.len();
    let n_water = waterStartTime.len();
    if n_land == 0 || n_water == 0 {
        return 0;
    }
    let INF: Int64 = 0x7FFFFFFFFFFFFFFF;

    fn upper_bound(arr: &Vec<(Int64, Int64, Int64)>, key: Int64) -> usize {
        let mut low: usize = 0;
        let mut high: usize = arr.len();
        while low < high {
            let mid = low + (high - low) / 2;
            if arr[mid].0 <= key {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        low
    }

    let mut water_arr: Vec<(Int64, Int64, Int64)> = Vec::new();
    for j in 0..n_water {
        let s = waterStartTime[j];
        let d = waterDuration[j];
        water_arr.push((s, d, s + d));
    }
    water_arr.sort_by(|a, b| a.0.cmp(&b.0));

    let mut left_min_dur_water = vec![INF; n_water];
    if n_water > 0 {
        left_min_dur_water[0] = water_arr[0].1;
        for i in 1..n_water {
            left_min_dur_water[i] = min(left_min_dur_water[i - 1], water_arr[i].1);
        }
    }

    let mut right_min_total_water = vec![INF; n_water];
    if n_water > 0 {
        right_min_total_water[n_water - 1] = water_arr[n_water - 1].2;
        for i in (0..n_water - 1).rev() {
            right_min_total_water[i] = min(right_min_total_water[i + 1], water_arr[i].2);
        }
    }

    let mut min_option1 = INF;
    for i in 0..n_land {
        let a_i = landStartTime[i] + landDuration[i];
        let pos = upper_bound(&water_arr, a_i);
        let candidate1 = if pos > 0 {
            a_i + left_min_dur_water[pos - 1]
        } else {
            INF
        };
        let candidate2 = if pos < n_water {
            right_min_total_water[pos]
        } else {
            INF
        };
        let total = min(candidate1, candidate2);
        if total < min_option1 {
            min_option1 = total;
        }
    }

    let mut land_arr: Vec<(Int64, Int64, Int64)> = Vec::new();
    for i in 0..n_land {
        let s = landStartTime[i];
        let d = landDuration[i];
        land_arr.push((s, d, s + d));
    }
    land_arr.sort_by(|a, b| a.0.cmp(&b.0));

    let mut left_min_dur_land = vec![INF; n_land];
    if n_land > 0 {
        left_min_dur_land[0] = land_arr[0].1;
        for i in 1..n_land {
            left_min_dur_land[i] = min(left_min_dur_land[i - 1], land_arr[i].1);
        }
    }

    let mut right_min_total_land = vec![INF; n_land];
    if n_land > 0 {
        right_min_total_land[n_land - 1] = land_arr[n_land - 1].2;
        for i in (0..n_land - 1).rev() {
            right_min_total_land[i] = min(right_min_total_land[i + 1], land_arr[i].2);
        }
    }

    let mut min_option2 = INF;
    for j in 0..n_water {
        let b_j = waterStartTime[j] + waterDuration[j];
        let pos = upper_bound(&land_arr, b_j);
        let candidate1 = if pos > 0 {
            b_j + left_min_dur_land[pos - 1]
        } else {
            INF
        };
        let candidate2 = if pos < n_land {
            right_min_total_land[pos]
        } else {
            INF
        };
        let total = min(candidate1, candidate2);
        if total < min_option2 {
            min_option2 = total;
        }
    }

    min(min_option1, min_option2)
}
